  acc += sampleScene(uv - vec2(s.x, 0.0)) * (2.0 / 16.0);
  acc += sampleScene(uv + vec2(0.0, s.y)) * (2.0 / 16.0);
  acc += sampleScene(uv - vec2(0.0, s.y)) * (2.0 / 16.0);
